+            AppSupervisorType::Forever,
+            AppSupervisorType::Unknown,
+        ] {
+            let json = serde_json::to_string(&typ).unwrap();
+            let back: AppSupervisorType = serde_json::from_str(&json).unwrap();
+            assert_eq!(back, typ, "Roundtrip failed for {:?}", typ);
+        }
+    }
